#[derive(Debug)]
enum UsState {
    Alaska,
}

enum Coin {
    Penny,
    Quarter(UsState),
}

fn main() {
    let coins = vec![Coin::Penny, Coin::Quarter(UsState::Alaska), Coin::Penny];
    let mut count = 0;
    for coin in coins {
        if let Coin::Quarter(state) = coin {
            println!("State quarter from {state:?}!");
        } else {
            count += 1;
        }
    }
    println!("count = {count}");
}

